const { pregunta, lead_tipo } = $input.first().json;

const segmentosMap = {
  KIDS: ['KIDS', 'GENERAL'],
  ADOLESCENTE: ['KIDS', 'ADULTOS', 'GENERAL'],
  ADULTO: ['ADULTOS', 'GENERAL'],
  AU_PAIR: ['AU_PAIR', 'GENERAL'],
  GENERAL: ['GENERAL']
};

const segmentos = segmentosMap[lead_tipo] || segmentosMap['GENERAL'];

return [{
  json: {
    pregunta: pregunta || 'información general',
    lead_tipo: lead_tipo || 'GENERAL',
    segmentos
  }
}];

const { segmentos } = $input.first().json;
const segmentosStr = segmentos.map(s => `'${s}'`).join(',');

const query = `SELECT id, categoria, segmento, titulo, contenido, activo FROM conocimiento_academia WHERE segmento IN (${segmentosStr}) AND activo = true ORDER BY categoria, segmento, titulo LIMIT 20`;

return [{ json: { query } }];

const rows = $input.all().map(i => i.json);
const normData = $('Mapear Segmentos').first().json;

if (!rows || rows.length === 0) {
  return [{
    json: {
      contexto_encontrado: false,
      contexto: 'Sin información disponible en la base de datos.',
      pregunta: normData.pregunta,
      lead_tipo: normData.lead_tipo,
      items_encontrados: 0
    }
  }];
}

const contexto = rows
  .map(r => `**${r.categoria}**\n${r.titulo}\n${r.contenido}`)
  .join('\n\n');

return [{
  json: {
    contexto_encontrado: true,
    contexto,
    pregunta: normData.pregunta,
    lead_tipo: normData.lead_tipo,
    items_encontrados: rows.length
  }
}];

const synth = $input.first().json;
const procData = $('Procesar Resultados').first().json;

let respuesta = 'No tengo esa información. Te paso al equipo de Fla para que te den los detalles.';
if (synth?.choices?.[0]?.message?.content) {
  respuesta = synth.choices[0].message.content.trim();
}

return [{
  json: {
    resultado: respuesta,
    confianza: procData.contexto_encontrado ? 'ALTA' : 'BAJA',
    items_consultados: procData.items_encontrados
  }
}];
